import React from "react";
import { useNavigate } from "react-router-dom";

function LandingPage() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* LEFT SIDE */}
      <div style={styles.left}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/3774/3774299.png"
          alt="doctors"
          style={styles.image}
        />
      </div>

      {/* RIGHT SIDE */}
      <div style={styles.right}>
        <div style={styles.card}>

          {/* Logo */}
          <div style={styles.logoContainer}>
            <img
              src="https://cdn-icons-png.flaticon.com/512/2966/2966485.png"
              alt="logo"
              style={styles.logo}
            />
            <h2 style={styles.logoText}>DocBook</h2>
          </div>

          <h3 style={styles.title}>Welcome Back</h3>

          <p style={styles.subtitle}>
            Book and manage your appointments easily
          </p>

          {/* Buttons */}
          <button
            style={styles.loginBtn}
            onClick={() => navigate("/login")}
          >
            LOGIN
          </button>

          <button
            style={styles.registerBtn}
            onClick={() => navigate("/register")}
          >
            REGISTER
          </button>

        </div>
      </div>

    </div>
  );
}

export default LandingPage;

const styles = {
  container: {
    display: "flex",
    height: "100vh",
    fontFamily: "Arial, sans-serif",
  },

  left: {
    flex: 1,
    backgroundColor: "#cfe8e8",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  image: {
    width: "70%",
  },

  right: {
    flex: 1,
    backgroundColor: "#f4f6f9",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  card: {
    backgroundColor: "white",
    padding: "40px",
    borderRadius: "12px",
    width: "300px",
    textAlign: "center",
    boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
  },

  logoContainer: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    gap: "10px",
    marginBottom: "15px",
  },

  logo: {
    width: "35px",
  },

  logoText: {
    margin: 0,
    color: "#2563EB",
  },

  title: {
    marginBottom: "10px",
  },

  subtitle: {
    fontSize: "14px",
    color: "#666",
    marginBottom: "20px",
  },

  loginBtn: {
    width: "100%",
    padding: "10px",
    backgroundColor: "#2563EB",
    color: "white",
    border: "none",
    borderRadius: "6px",
    marginBottom: "10px",
    cursor: "pointer",
  },

  registerBtn: {
    width: "100%",
    padding: "10px",
    backgroundColor: "#10B981",
    color: "white",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
  },
};
